import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"首都博物馆","description":"","frontmatter":{},"headers":[],"relativePath":"museums/capital-museum.md","filePath":"museums/capital-museum.md","lastUpdated":null}'),n={name:"museums/capital-museum.md"};function d(i,t,s,o,h,g){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="首都博物馆" tabindex="-1">首都博物馆 <a class="header-anchor" href="#首都博物馆" aria-label="Permalink to &quot;首都博物馆&quot;">​</a></h1><blockquote><p>&quot;了解北京历史文化的最佳窗口。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>首都博物馆位于北京市西城区，是国家一级博物馆，也是北京市属的综合性博物馆。首都博物馆以北京历史、文化、艺术为主要展示内容，是了解北京历史文化的最佳窗口。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-17:00（周一闭馆）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费（需预约）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">3-4小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁1号线木樨地站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区复兴门外大街16号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="创建" tabindex="-1">创建 <a class="header-anchor" href="#创建" aria-label="Permalink to &quot;创建&quot;">​</a></h3><p>首都博物馆创建于1981年，原址位于北京市东城区国子监街孔庙内。</p><h3 id="新馆建设" tabindex="-1">新馆建设 <a class="header-anchor" href="#新馆建设" aria-label="Permalink to &quot;新馆建设&quot;">​</a></h3><p>2001年，首都博物馆新馆立项。2006年5月，新馆正式对外开放。新馆由著名建筑师设计，建筑面积6.3万平方米，是一座现代化的大型博物馆。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="外观设计" tabindex="-1">外观设计 <a class="header-anchor" href="#外观设计" aria-label="Permalink to &quot;外观设计&quot;">​</a></h3><p>首都博物馆新馆外观设计独特，融合了传统与现代元素：</p><ul><li><strong>青铜展馆</strong>：椭圆形的青铜展馆，象征古代青铜器</li><li><strong>玉石展馆</strong>：矩形的玉石展馆，象征古代玉器</li><li><strong>中庭</strong>：两个展馆之间的玻璃中庭，象征历史与现代的对话</li></ul><h3 id="内部空间" tabindex="-1">内部空间 <a class="header-anchor" href="#内部空间" aria-label="Permalink to &quot;内部空间&quot;">​</a></h3><p>博物馆内部空间宽敞明亮，展厅众多。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>建筑面积</strong></td><td style="text-align:left;">6.3万平方米</td></tr><tr><td style="text-align:left;"><strong>展厅面积</strong></td><td style="text-align:left;">2.5万平方米</td></tr><tr><td style="text-align:left;"><strong>展厅数量</strong></td><td style="text-align:left;">16个</td></tr><tr><td style="text-align:left;"><strong>藏品数量</strong></td><td style="text-align:left;">约25万件</td></tr></tbody></table><h2 id="常设展览" tabindex="-1">常设展览 <a class="header-anchor" href="#常设展览" aria-label="Permalink to &quot;常设展览&quot;">​</a></h2><h3 id="北京历史文化展" tabindex="-1">北京历史文化展 <a class="header-anchor" href="#北京历史文化展" aria-label="Permalink to &quot;北京历史文化展&quot;">​</a></h3><p>这是首都博物馆的基本陈列，全面展示北京的历史文化。</p><h4 id="展览内容" tabindex="-1">展览内容 <a class="header-anchor" href="#展览内容" aria-label="Permalink to &quot;展览内容&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">展厅</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;">燕地青铜</td><td style="text-align:left;">北京出土的青铜器</td></tr><tr><td style="text-align:left;">玉器精品</td><td style="text-align:left;">北京出土的玉器</td></tr><tr><td style="text-align:left;">书法绘画</td><td style="text-align:left;">北京名家的书画</td></tr><tr><td style="text-align:left;">老北京民俗</td><td style="text-align:left;">老北京的生活习俗</td></tr><tr><td style="text-align:left;">京剧文化</td><td style="text-align:left;">京剧的历史与现状</td></tr></tbody></table><h3 id="老北京民俗展" tabindex="-1">老北京民俗展 <a class="header-anchor" href="#老北京民俗展" aria-label="Permalink to &quot;老北京民俗展&quot;">​</a></h3><p>这个展览生动展示了老北京的民俗风情。</p><h4 id="展示内容" tabindex="-1">展示内容 <a class="header-anchor" href="#展示内容" aria-label="Permalink to &quot;展示内容&quot;">​</a></h4><ul><li><strong>年节习俗</strong>：春节、元宵节等传统节日的习俗</li><li><strong>婚嫁习俗</strong>：老北京的婚嫁礼仪</li><li><strong>生育习俗</strong>：生子、满月、抓周等习俗</li><li><strong>寿诞习俗</strong>：过生日的习俗</li><li><strong>丧葬习俗</strong>：丧葬礼仪</li><li><strong>商业习俗</strong>：老北京的商业活动</li><li><strong>娱乐习俗</strong>：戏曲、曲艺、杂耍等</li></ul><h3 id="古代佛像艺术精品展" tabindex="-1">古代佛像艺术精品展 <a class="header-anchor" href="#古代佛像艺术精品展" aria-label="Permalink to &quot;古代佛像艺术精品展&quot;">​</a></h3><p>展示中国古代佛像艺术精品，包括石雕、木雕、铜铸等。</p><h3 id="燕地青铜艺术精品展" tabindex="-1">燕地青铜艺术精品展 <a class="header-anchor" href="#燕地青铜艺术精品展" aria-label="Permalink to &quot;燕地青铜艺术精品展&quot;">​</a></h3><p>展示北京出土的青铜器精品，包括商周青铜器、春秋战国青铜器等。</p><h2 id="珍贵文物" tabindex="-1">珍贵文物 <a class="header-anchor" href="#珍贵文物" aria-label="Permalink to &quot;珍贵文物&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">文物</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>伯矩鬲</strong></td><td style="text-align:left;">西周青铜器，首都博物馆镇馆之宝</td></tr><tr><td style="text-align:left;"><strong>班簋</strong></td><td style="text-align:left;">西周青铜器，有铭文</td></tr><tr><td style="text-align:left;"><strong>克盉、克罍</strong></td><td style="text-align:left;">西周青铜器，有铭文</td></tr><tr><td style="text-align:left;"><strong>堇鼎</strong></td><td style="text-align:left;">西周青铜器，首都地区出土最重的青铜礼器</td></tr><tr><td style="text-align:left;"><strong>青花凤首扁壶</strong></td><td style="text-align:left;">元代青花瓷器</td></tr></tbody></table><h2 id="特色展览" tabindex="-1">特色展览 <a class="header-anchor" href="#特色展览" aria-label="Permalink to &quot;特色展览&quot;">​</a></h2><h3 id="京剧文化展" tabindex="-1">京剧文化展 <a class="header-anchor" href="#京剧文化展" aria-label="Permalink to &quot;京剧文化展&quot;">​</a></h3><p>北京是京剧的发源地，京剧文化展展示了京剧的历史、流派、名家等。</p><h4 id="展览内容-1" tabindex="-1">展览内容 <a class="header-anchor" href="#展览内容-1" aria-label="Permalink to &quot;展览内容&quot;">​</a></h4><ul><li><strong>京剧起源</strong>：京剧的形成与发展</li><li><strong>京剧流派</strong>：四大名旦、四大须生等</li><li><strong>京剧脸谱</strong>：各种脸谱的含义</li><li><strong>京剧服饰</strong>：京剧的服装与道具</li></ul><h3 id="老北京戏楼展" tabindex="-1">老北京戏楼展 <a class="header-anchor" href="#老北京戏楼展" aria-label="Permalink to &quot;老北京戏楼展&quot;">​</a></h3><p>展示老北京戏楼的历史与文化。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="预约须知" tabindex="-1">预约须知 <a class="header-anchor" href="#预约须知" aria-label="Permalink to &quot;预约须知&quot;">​</a></h3><ol><li><strong>提前预约</strong>：必须提前在官网或微信预约</li><li><strong>实名制</strong>：需携带身份证</li><li><strong>周一闭馆</strong>：注意开放时间</li></ol><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约3-4小时）</strong>：</p><p>北京历史文化展 → 老北京民俗展 → 燕地青铜展 → 玉器精品展 → 京剧文化展 → 特展</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">1号线木樨地站C1口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">1路、4路、52路工会大楼站</td></tr><tr><td style="text-align:left;">自驾</td><td style="text-align:left;">博物馆有地下停车场</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>提前预约</strong>：必须提前预约</li><li><strong>讲解服务</strong>：可租借语音导览或请人工讲解</li><li><strong>餐饮服务</strong>：馆内有餐厅</li><li><strong>文创商店</strong>：可购买文创产品</li><li><strong>结合游览</strong>：可与中国军事博物馆一起游览</li></ol><h2 id="与国博对比" tabindex="-1">与国博对比 <a class="header-anchor" href="#与国博对比" aria-label="Permalink to &quot;与国博对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">对比项</th><th style="text-align:left;">首都博物馆</th><th style="text-align:left;">国家博物馆</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>定位</strong></td><td style="text-align:left;">北京市属</td><td style="text-align:left;">国家级</td></tr><tr><td style="text-align:left;"><strong>内容</strong></td><td style="text-align:left;">北京历史文化</td><td style="text-align:left;">中国通史</td></tr><tr><td style="text-align:left;"><strong>特色</strong></td><td style="text-align:left;">老北京民俗</td><td style="text-align:left;">国家宝藏</td></tr><tr><td style="text-align:left;"><strong>人流</strong></td><td style="text-align:left;">相对较少</td><td style="text-align:left;">较多</td></tr><tr><td style="text-align:left;"><strong>预约</strong></td><td style="text-align:left;">相对容易</td><td style="text-align:left;">较难预约</td></tr></tbody></table><p>首博更适合想了解北京本地文化的游客。</p><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">军事博物馆</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">国家级军事博物馆</td></tr><tr><td style="text-align:left;">中华世纪坛</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">文化建筑</td></tr><tr><td style="text-align:left;">玉渊潭公园</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">樱花名园</td></tr><tr><td style="text-align:left;">北京西站</td><td style="text-align:center;">地铁1站</td><td style="text-align:left;">火车站</td></tr></tbody></table><hr><p><strong>📍 地址</strong>：北京市西城区复兴门外大街16号 <strong>📞 电话</strong>：010-63393339 <strong>🌐 官网</strong>：<a href="http://www.capitalmuseum.org.cn" target="_blank" rel="noreferrer">www.capitalmuseum.org.cn</a><strong>📱 预约</strong>：关注&quot;首都博物馆&quot;微信公众号预约</p>',57)])])}const y=e(n,[["render",d]]);export{f as __pageData,y as default};
